function powxN(data) {
    const lines = data.split('\n');
    const x = parseFloat(lines[0]);
    const n = parseInt(lines[1], 10);
    let result = 1;
    const isNegative = n < 0;
    const absN = Math.abs(n);
    for (let i = 0; i < absN; i++) {
        result *= x;
    }
    return isNegative ? 1 / result : result;
}

