approaches.code_java:
class Solution {
    public double powxN(double x, int n) {
        if (n == 0) return 1;
        if (n < 0) return 1 / powxN(x, -n);
        if (n % 2 == 0) {
            double half = powxN(x, n / 2);
            return half * half;
        }
        else {
            return x * powxN(x, n - 1);
        }
    }
}

